import { useState } from "react";

/**
 * Lazy-loaded RSS thumbnail; hides itself on error (hotlink / CORS / 404).
 */
export default function ArticleThumbnail({ imageUrl, className, variant = "card" }) {
  const [show, setShow] = useState(Boolean(imageUrl));

  if (!imageUrl || !show) {
    return (
      <div
        className={`article-thumb-placeholder article-thumb-placeholder--${variant} ${className || ""}`.trim()}
        aria-hidden
      />
    );
  }

  return (
    <div className={`article-thumb-wrap article-thumb-wrap--${variant} ${className || ""}`.trim()}>
      <img
        src={imageUrl}
        alt=""
        loading="lazy"
        decoding="async"
        referrerPolicy="no-referrer-when-downgrade"
        onError={() => setShow(false)}
      />
    </div>
  );
}
